                </small>
            </div>
            <div>
                <button class="btn btn-primary" @click="onAddClick">
                    <em class="fa fa-plus mr-2" />Add Configuration
                </button>
            </div>
        </div>

        <div class="card">
            <div class="card-body p-0">
                <div v-if="configs.length === 0 && !isLoading" class="p-4 text-center text-muted">
                    No configurations found.
                </div>

                <div v-else class="table-responsive">
                    <table class="table table-sm table-bordered mb-0">
                        <thead class="thead-light">
                            <tr>
                                <th style="width: 60px;">Id</th>
                                <th style="width: 220px;">Entity Name</th>
                                <th style="width: 220px;">Target Index Table</th>
                                <th>Base From Clause</th>
                                <th style="width: 90px;">Enabled</th>
                                <th style="width: 90px;">CDC</th>
                                <th style="width: 140px;">Created On</th>
                                <th style="width: 120px;">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            <tr v-for="row in configs" :key="row.config_Id">
                                <td>{{ row.config_Id }}</td>
                                <td>{{ row.entity_Name }}</td>
                                <td>{{ row.target_Index_Table }}</td>
                                <td>
                                    <div class="text-truncate" :title="row.base_From_Clause">
                                        {{ row.base_From_Clause }}
                                    </div>
                                </td>
                                <td class="text-center">
                                    <span
                                        class="badge"
                                        :class="row.is_Enabled ? 'badge-success' : 'badge-secondary'"
                                    >
                                        {{ row.is_Enabled ? 'Yes' : 'No' }}
                                    </span>
                                </td>
                                <td class="text-center">
                                    <span
                                        class="badge"
                                        :class="row.is_Cdc_Enabled ? 'badge-info' : 'badge-secondary'"
                                    >
                                        {{ row.is_Cdc_Enabled ? 'Yes' : 'No' }}
                                    </span>
                                </td>
                                <td>
                                    {{ formatDate(row.created_on) }}
                                </td>
                             <td class="text-center">
                                <div class="d-inline-flex">
                                    <button
                                        class="btn btn-sm btn-outline-primary mr-1"
                                        @click="onEditClick(row)"
                                        title="Edit"
                                    >
                                        <em class="fa fa-pencil"></em>
                                    </button>

                                    <button
                                        class="btn btn-sm btn-outline-danger"
                                        @click="onDeleteClick(row)"
                                        title="Delete"
                                    >
                                        <em class="fa fa-trash"></em>
                                    </button>
                                </div>
                            </td>
                            </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <!-- Edit / Create drawer -->
        <div
            v-if="showForm"
            class="config-form-overlay"
        >
            <div class="config-form-panel">
                <div class="config-form-header d-flex justify-content-between align-items-center mb-3">
                    <h5 class="mb-0">
                        {{ isEditMode ? 'Edit Configuration' : 'Add Configuration' }}
                    </h5>
                    <button type="button" class="close" @click="closeForm">
                        <span aria-hidden="true">&times;</span>
                    </button>
                </div>

                <div class="config-form-body">
                    <div class="form-row">
                        <div class="form-group col-md-4">
                            <label>Entity Name<span class="text-danger">*</span></label>
                            <input
                                v-model="form.entity_Name"
                                class="form-control"
                                type="text"
                            />
                        </div>
                        <div class="form-group col-md-4">
                            <label>Target Index Table<span class="text-danger">*</span></label>
                            <input
                                v-model="form.target_Index_Table"
                                class="form-control"
                                type="text"
                            />
                        </div>
                        <div class="form-group col-md-4">
                            <label>CDC Capture Instance</label>
                            <input
                                v-model="form.cdc_capture_instance"
                                class="form-control"
                                type="text"
                            />
                        </div>
                    </div>

                    <div class="form-row">
                        <div class="form-group col-md-6">
                            <label>Entity Id Expression<span class="text-danger">*</span></label>
                            <input
                                v-model="form.entity_id_expr"
                                class="form-control"
                                type="text"
                            />
                        </div>
                        <div class="form-group col-md-6">
                            <label>Company Id Expression<span class="text-danger">*</span></label>
                            <input
                                v-model="form.company_id_expr"
                                class="form-control"
                                type="text"
                            />
                        </div>
                    </div>

                    <div class="form-row">
                        <div class="form-group col-md-6">
                            <label>Page Url Expression<span class="text-danger">*</span></label>
                            <input
                                v-model="form.page_url_expression"
                                class="form-control"
                                type="text"
                            />
                        </div>
                        <div class="form-group col-md-3 d-flex align-items-center">
                            <div class="form-check mt-4">
                                <input
                                    id="chkEnabled"
                                    v-model="form.is_Enabled"
                                    class="form-check-input"
                                    type="checkbox"
                                />
                                <label class="form-check-label" for="chkEnabled">
                                    Is Enabled
                                </label>
                            </div>
                        </div>
                        <div class="form-group col-md-3 d-flex align-items-center">
                            <div class="form-check mt-4">
                                <input
                                    id="chkCdcEnabled"
                                    v-model="form.is_Cdc_Enabled"
                                    class="form-check-input"
                                    type="checkbox"
                                />
                                <label class="form-check-label" for="chkCdcEnabled">
                                    Is CDC Enabled
                                </label>
                            </div>
                        </div>
                    </div>

                    <div class="form-group">
                        <label>Base FROM Clause<span class="text-danger">*</span></label>
                        <textarea
                            v-model="form.base_From_Clause"
                            class="form-control code-textarea"
                            rows="4"
                        />
                    </div>

                    <div class="form-group">
                        <label>WHERE Clause</label>
                        <textarea
                            v-model="form.where_clause"
                            class="form-control code-textarea"
                            rows="3"
                        />
                    </div>

                    <div class="form-group">
                        <label>Display Expression (JSON)</label>
                        <textarea
                            v-model="form.display_expression"
                            class="form-control code-textarea"
                            rows="4"
                        />
                    </div>

                    <div class="form-group">
                        <label>Search Expression</label>
                        <textarea
                            v-model="form.search_expression"
                            class="form-control code-textarea"
                            rows="3"
                        />
                    </div>

                    <div class="form-row">
                        <div class="form-group col-md-6">
                            <label>CDC Key Column</label>
                            <input
                                v-model="form.cdc_key_column"
                                class="form-control"
                                type="text"
                            />
                        </div>
                        <div class="form-group col-md-6">
                            <label>Created On</label>
                            <input
                                v-model="form.created_on"
                                class="form-control"
                                type="text"
                                disabled
                            />
                        </div>
                    </div>
                </div>

                <div class="config-form-footer d-flex justify-content-end mt-3">
                    <button class="btn btn-secondary mr-2" @click="closeForm">
                        Cancel
                    </button>
                    <button class="btn btn-primary" @click="onSave">
                        <em class="fa fa-floppy-o mr-2" />Save
                    </button>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import Loader from "../../components/Common/Loader.vue";
import DataService from "../../services/DataService";

export default {
    name: "SearchEntityConfig",
    components: {
        Loader,
    },
    data() {
        return {
            isLoading: false,
            configs: [],
            showForm: false,
            isEditMode: false,
            form: this.getEmptyForm(),
        };
    },
    created() {
        debugger
        this.loadConfigs();
    },
    methods: {
        getEmptyForm() {
            return {
                config_Id: 0,
                entity_Name: "",
                target_Index_Table: "",
                base_From_Clause: "",
                where_clause: "",
                entity_id_expr: "",
                company_id_expr: "",
                display_expression: "",
                search_expression: "",
                page_url_expression: "",
                is_Enabled: true,
                created_on: "",
                is_Cdc_Enabled: true,
                cdc_capture_instance: "",
                cdc_key_column: "",
            };
        },
        async loadConfigs() {
            this.isLoading = true;
            try {
                const response = await DataService.GetSearchEntityConfigList();
                this.configs = Array.isArray(response.data)
                    ? response.data
                    : response.data && response.data.data
                    ? response.data.data
                    : [];
            } catch (e) {
                console.error("Error loading Search_Entity_Config:", e);
            } finally {
                this.isLoading = false;
            }
        },
        onAddClick() {
            this.isEditMode = false;
            this.form = this.getEmptyForm();
            this.form.created_on = this.formatDateTime(new Date());
            this.showForm = true;
        },
        onEditClick(row) {
            this.isEditMode = true;
            this.form = {
                ...this.getEmptyForm(),
                ...row,
            };
            if (row.created_on) {
                this.form.created_on = this.formatDateTime(row.created_on);
            }
            this.showForm = true;
        },
        async onDeleteClick(row) {
            if (
                !window.confirm(
                    `Are you sure you want to delete config #${row.config_Id}?`
                )
            ) {
                return;
            }
            // Delete API is not implemented yet at backend; just info message for now.
            alert("Delete is not implemented yet for Search_Entity_Config.");
        },
        closeForm() {
            this.showForm = false;
        },
        async onSave() {
            if (
                !this.form.entity_Name ||
                !this.form.target_Index_Table ||
                !this.form.base_From_Clause ||
                !this.form.entity_id_expr ||
                !this.form.company_id_expr ||
                !this.form.page_url_expression
            ) {
                alert("Please fill in all mandatory fields.");
                return;
            }

            this.isLoading = true;
            try {
                const payload = { ...this.form };
                await DataService.SaveSearchEntityConfig(payload);
                this.showForm = false;
                await this.loadConfigs();
            } catch (e) {
                console.error("Error saving config:", e);
            } finally {
                this.isLoading = false;
            }
        },
        formatDate(value) {
            if (!value) return "";
            try {
                const d = new Date(value);
                if (isNaN(d.getTime())) return value;
                const mm = String(d.getMonth() + 1).padStart(2, "0");
                const dd = String(d.getDate()).padStart(2, "0");
                const yyyy = d.getFullYear();
                return `${mm}/${dd}/${yyyy}`;
            } catch {
                return value;
            }
        },
        formatDateTime(value) {
            try {
                const d = new Date(value);
                if (isNaN(d.getTime())) return value;
                const mm = String(d.getMonth() + 1).padStart(2, "0");
                const dd = String(d.getDate()).padStart(2, "0");
                const yyyy = d.getFullYear();
                const hh = String(d.getHours()).padStart(2, "0");
                const mi = String(d.getMinutes()).padStart(2, "0");
                const ss = String(d.getSeconds()).padStart(2, "0");
                return `${mm}/${dd}/${yyyy} ${hh}:${mi}:${ss}`;
            } catch {
                return value;
            }
        },
    },
};
</script>

